// A small, working CSV parser/serializer. Intentionally undocumented and untested.
function parseCSV(text, opts = {}) {
  const delimiter = opts.delimiter || ',';
  const headers = opts.headers !== false;
  const rows = [];
  let field = '';
  let row = [];
  let inQuotes = false;
  let i = 0;
  const pushField = () => { row.push(field); field = ''; };
  const pushRow = () => { rows.push(row); row = []; };
  while (i < text.length) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        if (text[i + 1] === '"') { field += '"'; i += 2; continue; }
        inQuotes = false; i += 1; continue;
      }
      field += ch; i += 1; continue;
    }
    if (ch === '"') { inQuotes = true; i += 1; continue; }
    if (ch === delimiter) { pushField(); i += 1; continue; }
    if (ch === '\r') { i += 1; continue; }
    if (ch === '\n') { pushField(); pushRow(); i += 1; continue; }
    field += ch; i += 1;
  }
  if (field.length > 0 || row.length > 0) { pushField(); pushRow(); }
  if (!headers) return rows;
  if (rows.length === 0) return [];
  const head = rows[0];
  return rows.slice(1).map((r) => {
    const obj = {};
    head.forEach((key, idx) => { obj[key] = r[idx]; });
    return obj;
  });
}

function stringifyCSV(rows, opts = {}) {
  const delimiter = opts.delimiter || ',';
  const esc = (v) => {
    const s = String(v);
    if (s.includes('"') || s.includes(delimiter) || s.includes('\n')) {
      return '"' + s.replace(/"/g, '""') + '"';
    }
    return s;
  };
  return rows.map((r) => r.map(esc).join(delimiter)).join('\n');
}

module.exports = { parseCSV, stringifyCSV };
